using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Change to your actual namespace

public class ReviewsController : Controller
{
    private YourDbContext db = new YourDbContext(); // Change to your actual DbContext

    public ActionResult Index(int productId)
    {
        var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
        return View(reviews);
    }

    [HttpPost]
    public ActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            db.Reviews.Add(review);
            db.SaveChanges();
            return RedirectToAction("Index", new { productId = review.ProductId });
        }
        return View("Index", db.Reviews.Where(r => r.ProductId == review.ProductId).ToList());
    }
}

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Content { get; set; }
    public string UserName { get; set; }
}

@using YourNamespace.Models // Change to your actual namespace
@model IEnumerable<Review>

<h2>Product Reviews</h2>

@using (Html.BeginForm("SubmitReview", "Reviews", FormMethod.Post))
{
    @Html.Hidden("ProductId", Model.FirstOrDefault()?.ProductId)
    <div>
